async (globalVars) => {
  const response = globalVars.response;
  try {
    let body = (response.body || '').trim();
    if (typeof body === 'string') {
      try { body = JSON.parse(body); } catch(e) { return []; }
    }
    const items = body?.items || [];
    const results = [];
    for (const item of items) {
      const goods = item?.item_data?.goods_model;
      if (!goods?.goods_id) continue;
      const tags = (goods.tag_list || []).map(t => t.text).filter(Boolean).join(',');
      const img = goods.thumb_url || goods.hd_thumb_url || goods.hd_url || '';
      results.push({
        title: (goods.goods_name || '').slice(0, 80),
        goods_id: String(goods.goods_id),
        price: '¥' + (goods.price_info || (goods.price / 100).toFixed(2)),
        sales: goods.sales_tip || '',
        tags: tags,
        img_url: img,
        url: 'https://mobile.pinduoduo.com/' + (goods.link_url || 'goods.html?goods_id=' + goods.goods_id)
      });
    }
    return results;
  } catch (e) { return []; }
}
